const u=[[1,1],[2,15],[4,1],[5,15],[7,1],[8,15],[10,1],[11,15]];function c(t){const n=t.getDay(),r=(n===0?-6:1)-n,e=new Date(t);return e.setDate(t.getDate()+r),e.setHours(0,0,0,0),e}function g(t){const n=t.getDay(),r=n===0?5:5-n,e=new Date(t);return e.setDate(t.getDate()+r),e.setHours(0,0,0,0),e}function D(t){return new Date(t.getFullYear(),t.getMonth(),1)}function h(t){return new Date(t.getFullYear(),t.getMonth()+1,0,0,0,0,0)}function M(t){const n=Math.floor(t.getMonth()/3)*3;return new Date(t.getFullYear(),n,1)}function d(t){const n=Math.floor(t.getMonth()/3)*3;return new Date(t.getFullYear(),n+3,0,0,0,0,0)}function y(t){const n=t.getFullYear();let r=null,e=1/0;for(const[a,l]of u){const o=new Date(n,a-1,l);a===1&&t.getMonth()===11&&o.setFullYear(n+1);const f=Math.abs(o-t);f<e&&(e=f,r=o)}return r}function w(t){const n=t.getFullYear();let r=null,e=1/0;for(let a=0;a<u.length;a++){const[l,o]=u[a],f=new Date(n,l-1,o);l===1&&t.getMonth()===11&&f.setFullYear(n+1);const s=new Date(f.getTime()-24*60*60*1e3);if(s>=t){const i=Math.abs(s-t);i<e&&(e=i,r=s)}}return r}const O={halfQuarter:{start:y,end:w},week:{start:c,end:g},month:{start:D,end:h},quarter:{start:M,end:d},day:{start:t=>t,end:t=>t}};export{O as r};
